import { isUndefined } from 'lodash-es';

import { AnnotationsMarkerGroup } from '../../../types/annotations.js';
import { SelectionState } from '../../../types/state.js';
import { buildMarkerBrightnessState } from '../../../utils/build-marker-brightness-state.js';
import { IndicatorData, IndicatorsDisplay } from '../types.js';

export const isAlwaysShown = (
  markerIndicatorDisplay?: IndicatorsDisplay,
  trackIndicatorDisplay?: IndicatorsDisplay,
) =>
  markerIndicatorDisplay === 'always' ||
  (isUndefined(markerIndicatorDisplay) && trackIndicatorDisplay === 'always');
export const isShownByInteraction = (
  data: AnnotationsMarkerGroup[] | undefined,
  markerId: string,
  indicatorsDisplay: IndicatorsDisplay | undefined,
) => indicatorsDisplay !== 'never' && data?.some(({ key }) => key === markerId);

export function buildIndicator(
  color: string,
  selection: SelectionState,
  markerId: string,
  start: Date | number,
  end: Date | number | undefined,
  priority?: number,
): IndicatorData {
  const isListHovered = selection.hoverGroupListKey === markerId;
  const state = buildMarkerBrightnessState(selection, markerId, isListHovered);

  return {
    end,
    start,
    color,
    state,
    priority,
  };
}

export const isAlwaysHidden = (
  markerIndicatorVisibility?: IndicatorsDisplay,
  trackIndicatorsVisibility?: IndicatorsDisplay,
) =>
  markerIndicatorVisibility === 'never' ||
  (isUndefined(markerIndicatorVisibility) &&
    trackIndicatorsVisibility === 'never');
